// Validate and sanitise incoming form data
const body = $input.first().json.body;

const clientName = (body.client_name || '').trim();
const domain = (body.domain || '').trim().toLowerCase().replace(/^https?:\/\//, '').replace(/\/$/, '');
const keywords = (body.keywords || []).map(k => k.trim().toLowerCase()).filter(Boolean);
const country = (body.country || 'US').trim().toUpperCase();
const engine = (body.engine || 'google').trim().toLowerCase();

// Basic validation
if (!clientName) throw new Error('client_name is required');
if (!domain) throw new Error('domain is required');
if (!keywords.length) throw new Error('At least one keyword is required');

// Simple domain format check
if (!/^[a-z0-9.-]+\.[a-z]{2,}$/.test(domain)) {
  throw new Error('Invalid domain format: ' + domain);
}

return [{ json: { clientName, domain, keywords, country, engine } }];
